import scala.xml._

object XmlParser {
  def parseXml(xmlString: String): Unit = {
    try {
      val xml = XML.loadString(xmlString)
      extractSettings(xml)
    } catch {
      case e: Exception => e.printStackTrace()
    }
  }

  private def extractSettings(node: Node): Unit = node match {
    case elem: Elem if elem.label == "setting" =>
      val name = (elem \ "@name").text
      val value = (elem \ "@value").text
      println(s"Setting: $name = $value")
      
    case _ => // Do nothing or throw exception for unsupported nodes
  }
}